SELECT DISTINCT geographical_region
FROM transactions
ORDER BY geographical_region;

SELECT COUNT(*) AS completed_transactions
FROM deal_status
WHERE status = 'completed' AND updated_at <= '2023-01-01';

SELECT COUNT(*) as summary_count
FROM financial_summary
WHERE financial_year = 2020;

SELECT COUNT(*) AS transaction_count
FROM transactions
WHERE sector_id = (SELECT sector_id FROM sectors WHERE sector_name = 'Healthcare');

SELECT revenues
FROM financial_summary
WHERE transaction_id = 1;

SELECT COUNT(*) AS transaction_count
FROM announcement_dates
WHERE announcement_date LIKE '2020-%';

SELECT status
FROM deal_status
WHERE status = 'completed';

SELECT COUNT(*) AS pending_transactions_count
FROM deal_status
WHERE status = 'pending';
